import{_ as d,o as e,c as r,ag as o}from"./chunks/framework.Cqf6AMW8.js";const m=JSON.parse('{"title":"Python selenium包","description":"Python selenium包常用函数参考，包括浏览器操作、元素定位、页面交互等功能。","frontmatter":{"title":"Python selenium包","description":"Python selenium包常用函数参考，包括浏览器操作、元素定位、页面交互等功能。","date":"2026-04-21T00:00:00.000Z","tags":["Python","selenium","爬虫","浏览器自动化"],"sidebar":"auto"},"headers":[],"relativePath":"docs/backend/python/py-bag-22-spider-selenium.md","filePath":"docs/backend/python/py-bag-22-spider-selenium.md","lastUpdated":1776715536000}'),c={name:"docs/backend/python/py-bag-22-spider-selenium.md"};function a(i,t,n,l,s,_){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="python-selenium包常用函数参考" tabindex="-1">Python selenium包常用函数参考 <a class="header-anchor" href="#python-selenium包常用函数参考" aria-label="Permalink to &quot;Python selenium包常用函数参考&quot;">​</a></h1><table tabindex="0"><thead><tr><th>函数名</th><th>必选参数</th><th>作用</th></tr></thead><tbody><tr><td><code>webdriver.Chrome([executable_path, options])</code></td><td>无</td><td>创建Chrome浏览器驱动</td></tr><tr><td><code>webdriver.Firefox([executable_path, options])</code></td><td>无</td><td>创建Firefox浏览器驱动</td></tr><tr><td><code>webdriver.Edge([executable_path, options])</code></td><td>无</td><td>创建Edge浏览器驱动</td></tr><tr><td><code>driver.get(url)</code></td><td>url: 网页地址</td><td>打开指定URL</td></tr><tr><td><code>driver.find_element(by, value)</code></td><td>by: 定位方式, value: 定位值</td><td>查找单个元素</td></tr><tr><td><code>driver.find_elements(by, value)</code></td><td>by: 定位方式, value: 定位值</td><td>查找多个元素</td></tr><tr><td><code>driver.find_element_by_id(id_)</code></td><td>id_: 元素ID</td><td>通过ID查找元素</td></tr><tr><td><code>driver.find_element_by_name(name)</code></td><td>name: 元素name属性</td><td>通过name查找元素</td></tr><tr><td><code>driver.find_element_by_xpath(xpath)</code></td><td>xpath: XPath表达式</td><td>通过XPath查找元素</td></tr><tr><td><code>driver.find_element_by_css_selector(css_selector)</code></td><td>css_selector: CSS选择器</td><td>通过CSS选择器查找元素</td></tr><tr><td><code>element.click()</code></td><td>无</td><td>点击元素</td></tr><tr><td><code>element.send_keys(*value)</code></td><td>value: 输入内容</td><td>向元素发送键盘输入</td></tr><tr><td><code>element.clear()</code></td><td>无</td><td>清除元素内容</td></tr><tr><td><code>element.text</code></td><td>无</td><td>获取元素文本</td></tr><tr><td><code>element.get_attribute(name)</code></td><td>name: 属性名</td><td>获取元素属性</td></tr><tr><td><code>element.is_displayed()</code></td><td>无</td><td>检查元素是否可见</td></tr><tr><td><code>element.is_enabled()</code></td><td>无</td><td>检查元素是否可用</td></tr><tr><td><code>element.is_selected()</code></td><td>无</td><td>检查元素是否被选中</td></tr><tr><td><code>driver.current_url</code></td><td>无</td><td>获取当前URL</td></tr><tr><td><code>driver.title</code></td><td>无</td><td>获取当前页面标题</td></tr><tr><td><code>driver.page_source</code></td><td>无</td><td>获取当前页面源码</td></tr><tr><td><code>driver.back()</code></td><td>无</td><td>浏览器后退</td></tr><tr><td><code>driver.forward()</code></td><td>无</td><td>浏览器前进</td></tr><tr><td><code>driver.refresh()</code></td><td>无</td><td>刷新页面</td></tr><tr><td><code>driver.quit()</code></td><td>无</td><td>关闭浏览器</td></tr><tr><td><code>driver.close()</code></td><td>无</td><td>关闭当前窗口</td></tr><tr><td><code>driver.switch_to.window(window_name)</code></td><td>window_name: 窗口句柄</td><td>切换到指定窗口</td></tr><tr><td><code>driver.switch_to.frame(frame_reference)</code></td><td>frame_reference: frame引用</td><td>切换到指定iframe</td></tr><tr><td><code>driver.implicitly_wait(time_to_wait)</code></td><td>time_to_wait: 等待时间(秒)</td><td>设置隐式等待时间</td></tr><tr><td><code>WebDriverWait(driver, timeout).until(method[, message])</code></td><td>driver: 驱动对象, timeout: 超时时间</td><td>显式等待</td></tr><tr><td><code>expected_conditions.presence_of_element_located(locator)</code></td><td>locator: 元素定位器</td><td>检查元素是否存在</td></tr><tr><td><code>expected_conditions.visibility_of_element_located(locator)</code></td><td>locator: 元素定位器</td><td>检查元素是否可见</td></tr></tbody></table><h2 id="常用参数说明" tabindex="-1">常用参数说明 <a class="header-anchor" href="#常用参数说明" aria-label="Permalink to &quot;常用参数说明&quot;">​</a></h2><h3 id="核心参数" tabindex="-1">核心参数 <a class="header-anchor" href="#核心参数" aria-label="Permalink to &quot;核心参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数名</th><th>类型</th><th>作用</th></tr></thead><tbody><tr><td><code>executable_path</code></td><td>str</td><td>浏览器驱动路径</td></tr><tr><td><code>options</code></td><td>Options</td><td>浏览器选项</td></tr><tr><td><code>url</code></td><td>str</td><td>要访问的网页地址</td></tr><tr><td><code>by</code></td><td>By</td><td>元素定位方式，如By.ID, By.NAME等</td></tr><tr><td><code>value</code></td><td>str</td><td>定位值</td></tr><tr><td><code>timeout</code></td><td>int</td><td>超时时间(秒)</td></tr><tr><td><code>locator</code></td><td>tuple</td><td>元素定位器，如(By.ID, &#39;element_id&#39;)</td></tr></tbody></table><h3 id="元素定位方式" tabindex="-1">元素定位方式 <a class="header-anchor" href="#元素定位方式" aria-label="Permalink to &quot;元素定位方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>定位方式</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>By.ID</code></td><td>通过元素ID定位</td><td><code>driver.find_element(By.ID, &#39;username&#39;)</code></td></tr><tr><td><code>By.NAME</code></td><td>通过元素name属性定位</td><td><code>driver.find_element(By.NAME, &#39;password&#39;)</code></td></tr><tr><td><code>By.CLASS_NAME</code></td><td>通过元素class属性定位</td><td><code>driver.find_element(By.CLASS_NAME, &#39;btn&#39;)</code></td></tr><tr><td><code>By.TAG_NAME</code></td><td>通过元素标签名定位</td><td><code>driver.find_element(By.TAG_NAME, &#39;input&#39;)</code></td></tr><tr><td><code>By.LINK_TEXT</code></td><td>通过链接文本定位</td><td><code>driver.find_element(By.LINK_TEXT, &#39;登录&#39;)</code></td></tr><tr><td><code>By.PARTIAL_LINK_TEXT</code></td><td>通过部分链接文本定位</td><td><code>driver.find_element(By.PARTIAL_LINK_TEXT, &#39;登&#39;)</code></td></tr><tr><td><code>By.XPATH</code></td><td>通过XPath表达式定位</td><td><code>driver.find_element(By.XPATH, &#39;//input[@id=&quot;username&quot;]&#39;)</code></td></tr><tr><td><code>By.CSS_SELECTOR</code></td><td>通过CSS选择器定位</td><td><code>driver.find_element(By.CSS_SELECTOR, &#39;#username&#39;)</code></td></tr></tbody></table><h3 id="浏览器选项参数" tabindex="-1">浏览器选项参数 <a class="header-anchor" href="#浏览器选项参数" aria-label="Permalink to &quot;浏览器选项参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数名</th><th>类型</th><th>作用</th></tr></thead><tbody><tr><td><code>--headless</code></td><td>str</td><td>无头模式，不显示浏览器窗口</td></tr><tr><td><code>--disable-gpu</code></td><td>str</td><td>禁用GPU加速</td></tr><tr><td><code>--window-size</code></td><td>str</td><td>设置浏览器窗口大小</td></tr><tr><td><code>--user-agent</code></td><td>str</td><td>设置用户代理</td></tr><tr><td><code>--proxy-server</code></td><td>str</td><td>设置代理服务器</td></tr></tbody></table>',9)])])}const u=d(c,[["render",a]]);export{m as __pageData,u as default};
